import { create } from 'zustand';
import { devtools } from 'zustand/middleware';
import type { User } from '@/types';

interface AuthState {
  user: User | null;
  isLoading: boolean;
  isAuthenticated: boolean;
  error: string | null;
}

interface AuthActions {
  setUser:     (user: User) => void;
  clearUser:   () => void;
  setLoading:  (loading: boolean) => void;
  setError:    (error: string | null) => void;
}

type AuthStore = AuthState & AuthActions;

const useAuthStore = create<AuthStore>()(
  devtools(
    (set) => ({
      user:            null,
      isLoading:       true,
      isAuthenticated: false,
      error:           null,

      setUser:    (user)    => set({ user, isAuthenticated: true,  isLoading: false, error: null }, false, 'setUser'),
      clearUser:  ()        => set({ user: null, isAuthenticated: false, isLoading: false },        false, 'clearUser'),
      setLoading: (isLoading) => set({ isLoading },                                                 false, 'setLoading'),
      setError:   (error)   => set({ error, isLoading: false },                                     false, 'setError'),
    }),
    { name: 'AuthStore' }
  )
);

export default useAuthStore;
