import {
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  signOut,
  updateProfile,
  onAuthStateChanged,
  type User as FirebaseUser,
  type Unsubscribe,
} from 'firebase/auth';
import { auth } from '@/lib/firebase';
import { logError, logInfo } from '@/lib/logger';
import type { User } from '@/types';

export function mapFirebaseUser(firebaseUser: FirebaseUser): User {
  return {
    uid:          firebaseUser.uid,
    email:        firebaseUser.email ?? '',
    displayName:  firebaseUser.displayName ?? 'User',
    phoneNumber:  firebaseUser.phoneNumber,
    kycVerified:  false,
    createdAt:    firebaseUser.metadata.creationTime ?? new Date().toISOString(),
  };
}

export async function registerWithEmail(
  email: string,
  password: string,
  displayName: string
): Promise<User> {
  logInfo('[authService] Registering new user', { email });
  try {
    const credential = await createUserWithEmailAndPassword(auth, email, password);
    await updateProfile(credential.user, { displayName });
    logInfo('[authService] Registration successful', { uid: credential.user.uid });
    return mapFirebaseUser(credential.user);
  } catch (error) {
    logError('[authService] Registration failed', error);
    throw mapAuthError(error);
  }
}

export async function loginWithEmail(
  email: string,
  password: string
): Promise<User> {
  logInfo('[authService] Logging in', { email });
  try {
    const credential = await signInWithEmailAndPassword(auth, email, password);
    logInfo('[authService] Login successful', { uid: credential.user.uid });
    return mapFirebaseUser(credential.user);
  } catch (error) {
    logError('[authService] Login failed', error);
    throw mapAuthError(error);
  }
}

export async function logout(): Promise<void> {
  logInfo('[authService] Logging out');
  try {
    await signOut(auth);
    logInfo('[authService] Logout successful');
  } catch (error) {
    logError('[authService] Logout failed', error);
    throw mapAuthError(error);
  }
}

export function subscribeToAuthState(
  callback: (user: User | null) => void
): Unsubscribe {
  return onAuthStateChanged(auth, (firebaseUser) => {
    if (firebaseUser) {
      callback(mapFirebaseUser(firebaseUser));
    } else {
      callback(null);
    }
  });
}

function mapAuthError(error: unknown): Error {
  if (error instanceof Error && 'code' in error) {
    const code = (error as { code: string }).code;
    const messages: Record<string, string> = {
      'auth/email-already-in-use':   'An account with this email already exists.',
      'auth/invalid-email':          'Please enter a valid email address.',
      'auth/weak-password':          'Password must be at least 6 characters.',
      'auth/user-not-found':         'No account found with this email.',
      'auth/wrong-password':         'Incorrect password. Please try again.',
      'auth/too-many-requests':      'Too many attempts. Please wait and try again.',
      'auth/network-request-failed': 'Network error. Check your connection.',
      'auth/invalid-credential':     'Invalid credentials. Please try again.',
    };
    return new Error(messages[code] ?? 'Authentication failed. Please try again.');
  }
  return new Error('An unexpected error occurred.');
}
