type LogLevel = 'info' | 'warn' | 'error' | 'debug';
type LogContext = Record<string, unknown>;

interface LogEntry {
  level: LogLevel;
  message: string;
  context?: LogContext;
  timestamp: string;
}

const isDevelopment = process.env.NODE_ENV === 'development';

function formatEntry(entry: LogEntry): string {
  const base = `[${entry.timestamp}] [${entry.level.toUpperCase()}] ${entry.message}`;
  if (entry.context && Object.keys(entry.context).length > 0) {
    return `${base} | ${JSON.stringify(entry.context)}`;
  }
  return base;
}

function buildEntry(level: LogLevel, message: string, context?: LogContext): LogEntry {
  return { level, message, context, timestamp: new Date().toISOString() };
}

function emit(entry: LogEntry): void {
  const formatted = formatEntry(entry);
  switch (entry.level) {
    case 'info': console.info(formatted); break;
    case 'warn': console.warn(formatted); break;
    case 'error': console.error(formatted); break;
    case 'debug': if (isDevelopment) console.debug(formatted); break;
  }
}

export function logInfo(message: string, context?: LogContext): void {
  emit(buildEntry('info', message, context));
}

export function logWarn(message: string, context?: LogContext): void {
  emit(buildEntry('warn', message, context));
}

export function logError(message: string, errorOrContext?: unknown): void {
  let context: LogContext | undefined;
  if (errorOrContext instanceof Error) {
    context = {
      name: errorOrContext.name,
      message: errorOrContext.message,
      stack: isDevelopment ? errorOrContext.stack : undefined,
    };
  } else if (typeof errorOrContext === 'object' && errorOrContext !== null) {
    context = errorOrContext as LogContext;
  }
  emit(buildEntry('error', message, context));
}

export function logDebug(message: string, context?: LogContext): void {
  emit(buildEntry('debug', message, context));
}
